select "A", "B", (
       select count(1)
       from "testTable1" "inner"
       where ("inner"."B" = "outer"."A")
 ) from "testTable1" "outer";

select "A", "B", (
 	select count(1)
 	from "testTable1" "inner"
 	where ("inner"."B" = "outer"."A") and ("outer"."A" is not null)
 ) from "testTable1" "outer";
